import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def get_packages(data):
    pkgs = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                pkgs[(name, pkg['id'])] = pkg['resolvedVersion']
    return pkgs

b = get_packages(baseline)
a = get_packages(after)
print('Differences:' if b != a else 'No differences - conversion is version-neutral')
for k in sorted(set(list(b.keys()) + list(a.keys()))):
    bv, av = b.get(k), a.get(k)
    if bv != av:
        print(f'  {k}: {bv} -> {av}')
